package main

import (
	"bytes"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
)

// Minimal ELF64 little-endian patcher for retargeting malloc relocations to a wrapper.
// Hard rules: no debug/elf, no external deps.

const (
	EI_NIDENT = 16

	// e_ident offsets
	EI_CLASS = 4
	EI_DATA  = 5

	ELFCLASS64 = 2
	ELFDATA2LSB = 1

	// Section types
	SHT_NULL   = 0
	SHT_SYMTAB = 2
	SHT_STRTAB = 3
	SHT_RELA   = 4
	SHT_DYNSYM = 11
)

type elf64Ehdr struct {
	Ident     [16]byte
	Type      uint16
	Machine   uint16
	Version   uint32
	Entry     uint64
	Phoff     uint64
	Shoff     uint64
	Flags     uint32
	Ehsize    uint16
	Phentsize uint16
	Phnum     uint16
	Shentsize uint16
	Shnum     uint16
	Shstrndx  uint16
}

type elf64Shdr struct {
	Name      uint32
	Type      uint32
	Flags     uint64
	Addr      uint64
	Off       uint64
	Size      uint64
	Link      uint32
	Info      uint32
	Addralign uint64
	Entsize   uint64
}

type elf64Sym struct {
	Name  uint32
	Info  byte
	Other byte
	Shndx uint16
	Value uint64
	Size  uint64
}

type elf64Rela struct {
	Off    uint64
	Info   uint64
	Addend int64
}

func elf64RelaSym(info uint64) uint32 { return uint32(info >> 32) }
func elf64RelaType(info uint64) uint32 { return uint32(info & 0xffffffff) }
func elf64RelaInfo(sym uint32, typ uint32) uint64 { return (uint64(sym) << 32) | uint64(typ) }

func readAtFull(f *os.File, b []byte, off int64) error {
	n, err := f.ReadAt(b, off)
	if err != nil && err != io.EOF {
		return err
	}
	if n != len(b) {
		return io.ErrUnexpectedEOF
	}
	return nil
}

func cstr(tab []byte, off uint32) (string, error) {
	if off >= uint32(len(tab)) {
		return "", fmt.Errorf("string offset %d out of range (tab size %d)", off, len(tab))
	}
	s := tab[off:]
	i := bytes.IndexByte(s, 0)
	if i < 0 {
		return "", errors.New("unterminated string")
	}
	return string(s[:i]), nil
}

func usage() {
	fmt.Fprintf(os.Stderr, "usage: %s <input_elf> <output_elf> [wrapper_symbol]\n", filepath.Base(os.Args[0]))
	os.Exit(2)
}

func main() {
	if len(os.Args) != 3 && len(os.Args) != 4 {
		usage()
	}
	inPath := os.Args[1]
	outPath := os.Args[2]
	wrapper := "logged_malloc"
	if len(os.Args) == 4 {
		wrapper = os.Args[3]
	}

	in, err := os.Open(inPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "open input: %v\n", err)
		os.Exit(1)
	}
	defer in.Close()

	st, err := in.Stat()
	if err != nil {
		fmt.Fprintf(os.Stderr, "stat input: %v\n", err)
		os.Exit(1)
	}
	if st.Size() < 64 {
		fmt.Fprintf(os.Stderr, "input too small to be ELF: %d bytes\n", st.Size())
		os.Exit(1)
	}

	// Read ELF header (64 bytes for ELF64)
	var eh elf64Ehdr
	hdrBuf := make([]byte, 64)
	if err := readAtFull(in, hdrBuf, 0); err != nil {
		fmt.Fprintf(os.Stderr, "read ELF header: %v\n", err)
		os.Exit(1)
	}
	if err := binary.Read(bytes.NewReader(hdrBuf), binary.LittleEndian, &eh); err != nil {
		fmt.Fprintf(os.Stderr, "parse ELF header: %v\n", err)
		os.Exit(1)
	}
	if string(eh.Ident[0:4]) != "\x7fELF" {
		fmt.Fprintf(os.Stderr, "not an ELF file (bad magic)\n")
		os.Exit(1)
	}
	if eh.Ident[EI_CLASS] != ELFCLASS64 {
		fmt.Fprintf(os.Stderr, "unsupported ELF class %d (need 64-bit)\n", eh.Ident[EI_CLASS])
		os.Exit(1)
	}
	if eh.Ident[EI_DATA] != ELFDATA2LSB {
		fmt.Fprintf(os.Stderr, "unsupported ELF data encoding %d (need little-endian)\n", eh.Ident[EI_DATA])
		os.Exit(1)
	}
	if eh.Shoff == 0 || eh.Shentsize == 0 || eh.Shnum == 0 {
		fmt.Fprintf(os.Stderr, "ELF missing section headers (no Shoff/Shnum)\n")
		os.Exit(1)
	}

	// Read section headers
	shdrs := make([]elf64Shdr, eh.Shnum)
	shTableSize := int64(eh.Shentsize) * int64(eh.Shnum)
	shBuf := make([]byte, shTableSize)
	if err := readAtFull(in, shBuf, int64(eh.Shoff)); err != nil {
		fmt.Fprintf(os.Stderr, "read section headers: %v\n", err)
		os.Exit(1)
	}
	for i := 0; i < int(eh.Shnum); i++ {
		start := i * int(eh.Shentsize)
		end := start + int(eh.Shentsize)
		if end > len(shBuf) {
			fmt.Fprintf(os.Stderr, "section header buffer overrun\n")
			os.Exit(1)
		}
		// Only support standard 64-byte shdr size.
		if eh.Shentsize < 64 {
			fmt.Fprintf(os.Stderr, "unsupported Shentsize %d (need >= 64)\n", eh.Shentsize)
			os.Exit(1)
		}
		var sh elf64Shdr
		if err := binary.Read(bytes.NewReader(shBuf[start:start+64]), binary.LittleEndian, &sh); err != nil {
			fmt.Fprintf(os.Stderr, "parse shdr %d: %v\n", i, err)
			os.Exit(1)
		}
		shdrs[i] = sh
	}

	if eh.Shstrndx == 0 || int(eh.Shstrndx) >= len(shdrs) {
		fmt.Fprintf(os.Stderr, "invalid Shstrndx %d\n", eh.Shstrndx)
		os.Exit(1)
	}
	shstr := shdrs[eh.Shstrndx]
	shstrTab := make([]byte, shstr.Size)
	if err := readAtFull(in, shstrTab, int64(shstr.Off)); err != nil {
		fmt.Fprintf(os.Stderr, "read .shstrtab: %v\n", err)
		os.Exit(1)
	}

	secName := func(i int) string {
		if i < 0 || i >= len(shdrs) {
			return "<badsec>"
		}
		n, err := cstr(shstrTab, shdrs[i].Name)
		if err != nil {
			return "<badname>"
		}
		return n
	}

	// Locate .dynsym and its associated string table via sh_link.
	dynsymIdx := -1
	for i, sh := range shdrs {
		if sh.Type == SHT_DYNSYM {
			dynsymIdx = i
			break
		}
	}
	if dynsymIdx < 0 {
		fmt.Fprintf(os.Stderr, "missing .dynsym (SHT_DYNSYM)\n")
		os.Exit(1)
	}
	dynsym := shdrs[dynsymIdx]
	if dynsym.Entsize == 0 {
		fmt.Fprintf(os.Stderr, ".dynsym has zero Entsize\n")
		os.Exit(1)
	}
	if dynsym.Link == 0 || int(dynsym.Link) >= len(shdrs) {
		fmt.Fprintf(os.Stderr, ".dynsym has invalid sh_link %d\n", dynsym.Link)
		os.Exit(1)
	}
	dynstr := shdrs[dynsym.Link]
	if dynstr.Type != SHT_STRTAB {
		fmt.Fprintf(os.Stderr, ".dynsym sh_link does not point to STRTAB (got type %d)\n", dynstr.Type)
		os.Exit(1)
	}

	dynstrTab := make([]byte, dynstr.Size)
	if err := readAtFull(in, dynstrTab, int64(dynstr.Off)); err != nil {
		fmt.Fprintf(os.Stderr, "read .dynstr: %v\n", err)
		os.Exit(1)
	}

	// Read dynsym entries
	if dynsym.Size%uint64(dynsym.Entsize) != 0 {
		fmt.Fprintf(os.Stderr, ".dynsym size not multiple of entsize\n")
		os.Exit(1)
	}
	nSyms := int(dynsym.Size / uint64(dynsym.Entsize))
	symBuf := make([]byte, dynsym.Size)
	if err := readAtFull(in, symBuf, int64(dynsym.Off)); err != nil {
		fmt.Fprintf(os.Stderr, "read .dynsym: %v\n", err)
		os.Exit(1)
	}
	syms := make([]elf64Sym, nSyms)
	for i := 0; i < nSyms; i++ {
		start := i * int(dynsym.Entsize)
		// We only support ELF64 sym size 24 bytes.
		if int(dynsym.Entsize) < 24 {
			fmt.Fprintf(os.Stderr, "unsupported dynsym entsize %d\n", dynsym.Entsize)
			os.Exit(1)
		}
		var s elf64Sym
		if err := binary.Read(bytes.NewReader(symBuf[start:start+24]), binary.LittleEndian, &s); err != nil {
			fmt.Fprintf(os.Stderr, "parse dynsym[%d]: %v\n", i, err)
			os.Exit(1)
		}
		syms[i] = s
	}

	nameToIndex := map[string]uint32{}
	for i, s := range syms {
		n, err := cstr(dynstrTab, s.Name)
		if err != nil {
			continue
		}
		// Keep first occurrence; symbol resolution uses versioning too, but
		// for our harness we expect unique names.
		if _, ok := nameToIndex[n]; !ok {
			nameToIndex[n] = uint32(i)
		}
	}

	mallocIdx, ok := nameToIndex["malloc"]
	if !ok {
		fmt.Fprintf(os.Stderr, "missing symbol in .dynsym: malloc\n")
		os.Exit(1)
	}
	wrapperIdx, ok := nameToIndex[wrapper]
	if !ok {
		fmt.Fprintf(os.Stderr, "missing symbol in .dynsym: %s\n", wrapper)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "dynsym: malloc idx=%d, %s idx=%d\n", mallocIdx, wrapper, wrapperIdx)

	// Load entire file into memory for patching.
	data, err := os.ReadFile(inPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "read input: %v\n", err)
		os.Exit(1)
	}
	origPrefix := append([]byte(nil), data[:64]...)

	patched := 0
	// Scan relocation sections (SHT_RELA). We only rewrite r_info sym index.
	for si, sh := range shdrs {
		if sh.Type != SHT_RELA {
			continue
		}
		if sh.Entsize == 0 {
			continue
		}
		if sh.Size%uint64(sh.Entsize) != 0 {
			continue
		}
		n := int(sh.Size / uint64(sh.Entsize))
		secOff := int64(sh.Off)
		secEnd := secOff + int64(sh.Size)
		if secOff < 0 || secEnd < secOff || secEnd > int64(len(data)) {
			fmt.Fprintf(os.Stderr, "skip relocation section %d (%s): out of file bounds\n", si, secName(si))
			continue
		}
		secBytes := data[secOff:secEnd]

		// Only support ELF64 Rela size 24.
		if sh.Entsize < 24 {
			fmt.Fprintf(os.Stderr, "skip relocation section %d (%s): entsize %d too small\n", si, secName(si), sh.Entsize)
			continue
		}

		for i := 0; i < n; i++ {
			entOff := i * int(sh.Entsize)
			var r elf64Rela
			if err := binary.Read(bytes.NewReader(secBytes[entOff:entOff+24]), binary.LittleEndian, &r); err != nil {
				fmt.Fprintf(os.Stderr, "parse rela %s[%d]: %v\n", secName(si), i, err)
				os.Exit(1)
			}
			oldSym := elf64RelaSym(r.Info)
			typ := elf64RelaType(r.Info)
			if oldSym != mallocIdx {
				continue
			}

			newInfo := elf64RelaInfo(wrapperIdx, typ)
			// Patch r_info in-place at offset 8 within Rela.
			binary.LittleEndian.PutUint64(secBytes[entOff+8:entOff+16], newInfo)
			patched++
			fmt.Fprintf(os.Stderr, "patched relocation: section=%s idx=%d r_offset=0x%x type=%d sym %d(malloc) -> %d(%s)\n",
				secName(si), i, r.Off, typ, oldSym, wrapperIdx, wrapper)
		}
	}

	if patched == 0 {
		fmt.Fprintf(os.Stderr, "no applicable relocations found targeting malloc (sym idx %d)\n", mallocIdx)
		os.Exit(1)
	}

	// Ensure first 64 bytes unchanged.
	if !bytes.Equal(origPrefix, data[:64]) {
		fmt.Fprintf(os.Stderr, "internal error: ELF header prefix (0..63) changed\n")
		os.Exit(1)
	}

	// Write output.
	if err := os.WriteFile(outPath, data, 0755); err != nil {
		fmt.Fprintf(os.Stderr, "write output: %v\n", err)
		os.Exit(1)
	}
	if err := os.Chmod(outPath, 0755); err != nil {
		fmt.Fprintf(os.Stderr, "chmod output: %v\n", err)
		os.Exit(1)
	}

	fmt.Fprintf(os.Stderr, "done: wrote %s (patched %d relocations)\n", outPath, patched)
}
